1	import { Component, OnInit } from '@angular/core';
2	import { FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';
3	import { CommonModule } from '@angular/common';
4	import { ReactiveFormsModule } from '@angular/forms';
5	import { MatFormFieldModule } from '@angular/material/form-field';
6	import { MatInputModule } from '@angular/material/input';
7	import { MatDatepickerModule } from '@angular/material/datepicker';
8	import { MatNativeDateModule } from '@angular/material/core';
9	import { MatButtonModule } from '@angular/material/button';
10	import { MatIconModule } from '@angular/material/icon';
11	import { MatSelectModule } from '@angular/material/select';
12	import {
13	  MatAutocompleteModule,
14	  MatAutocompleteSelectedEvent
15	} from '@angular/material/autocomplete';
16	import { MatSnackBar, MatSnackBarModule } from '@angular/material/snack-bar';
17	import { TrackingService } from 'src/app/helpers/services/tracking.service';
18	import { itemService } from 'src/app/helpers/services/main.service';
19	import decode from 'jwt-decode';
20	import { Observable } from 'rxjs';
21	import { map, startWith } from 'rxjs/operators';
22	
23	export interface FactoryProdOrderRow {
24	  id: number;
25	  prodOrderNo: string;
26	  prodReferenceNo?: string | null;
27	  vendorCode?: string;
28	  material_arrival_date?: string | null;
29	  mass_prod_start_date?: string | null;
30	  assembly_start_date?: string | null;
31	  actual_prod_complete?: string | null;
32	  packing_start_date?: string | null;
33	  qc_inspection_date?: string | null;
34	  actual_etd?: string | null;
35	}
36	
37	export interface FactoryListRow {
38	  id: number;
39	  factory_name: string | null;
40	  factory_nickname: string | null;
41	  sort_order: number | null;
42	}
43	
44	export interface FactorySampleOfferRow {
45	  sample_id_pk: number;
46	  sample_name?: string | null;
47	  quantity?: number | null;
48	  fob_cost?: number | null;
49	  office_location?: string | null;
50	  status?: string | null;
51	  notes?: string | null;
52	}
53	
54	@Component({
55	  selector: 'app-factory',
56	  templateUrl: './factory.component.html',
57	  styleUrls: ['./factory.component.scss'],
58	  standalone: true,
59	  imports: [
60	    CommonModule,
61	    ReactiveFormsModule,
62	    MatFormFieldModule,
63	    MatInputModule,
64	    MatDatepickerModule,
65	    MatNativeDateModule,
66	    MatButtonModule,
67	    MatIconModule,
68	    MatSelectModule,
69	    MatAutocompleteModule,
70	    MatSnackBarModule
71	  ]
72	})
73	export class FactoryComponent implements OnInit {
74	  factoryForm: FormGroup;
75	  sampleOfferForm: FormGroup;
76	  /** Searchable factory field (value is string while typing, or FactoryListRow when picked). */
77	  factorySearchCtrl = new FormControl<string | FactoryListRow>('');
78	  filteredFactories$: Observable<FactoryListRow[]>;
79	
80	  prodOrders: FactoryProdOrderRow[] = [];
81	  factories: FactoryListRow[] = [];
82	  loadingList = false;
83	  loadingFactories = false;
84	  saving = false;
85	  savingOffer = false;
86	  loadingOffers = false;
87	  isVendor = false;
88	  private vendorFactoryId: number | null = null;
89	  recentOffers: FactorySampleOfferRow[] = [];
90	  /** Total production orders matching filters (getProdOrderHeader-style pagination). */
91	  prodOrderTotalCount = 0;
92	
93	  readonly displayFactoryFn = (v: FactoryListRow | string | null): string => {
94	    if (v == null) {
95	      return '';
96	    }
97	    if (typeof v === 'string') {
98	      return v;
99	    }
100	    return this.factoryLabel(v);
101	  };
102	
103	  constructor(
104	    private fb: FormBuilder,
105	    private tracking: TrackingService,
106	    private coreApi: itemService,
107	    private snackBar: MatSnackBar
108	  ) {
109	    this.factoryForm = this.fb.group({
110	      factoryId: [null as number | null, Validators.required],
111	      prodOrderId: [null as number | null, Validators.required],
112	      materialArrivalDate: [null as Date | null],
113	      massProdStartDate: [null as Date | null],
114	      assemblyStartDate: [null as Date | null],
115	      actualProdComplete: [null as Date | null],
116	      packingStartDate: [null as Date | null],
117	      qcInspectionDate: [null as Date | null],
118	      actualEtd: [null as Date | null]
119	    });
120	
121	    this.sampleOfferForm = this.fb.group({
122	      destinationOffice: ['Ningbo', Validators.required],
123	      sampleName: ['', Validators.required],
124	      quantity: [null as number | null],
125	      fobCost: [null as number | null],
126	      notes: ['']
127	    });
128	
129	    this.filteredFactories$ = this.factorySearchCtrl.valueChanges.pipe(
130	      startWith(''),
131	      map((value) => this.filterFactoryList(this.factorySearchQueryFromValue(value)))
132	    );
133	  }
134	
135	  ngOnInit(): void {
136	    this.readTokenContext();
137	    this.loadingFactories = true;
138	    this.coreApi.listFactories().subscribe({
139	      next: (list) => {
140	        const full = list || [];
141	        if (this.isVendor) {
142	          if (this.vendorFactoryId != null) {
143	            this.factories = full.filter((f) => f.id === this.vendorFactoryId);
144	          } else {
145	            this.factories = [];
146	          }
147	        } else {
148	          this.factories = full;
149	        }
150	        this.loadingFactories = false;
151	        this.applyVendorFactoryPreset();
152	        this.applyFactorySearchDisabledState();
153	        this.loadOrders();
154	        this.loadSampleOffers();
155	      },
156	      error: () => {
157	        this.loadingFactories = false;
158	        this.applyFactorySearchDisabledState();
159	        this.snackBar.open('Could not load factories', 'Dismiss', { duration: 5000 });
160	        this.loadOrders();
161	        this.loadSampleOffers();
162	      }
163	    });
164	  }
165	
166	  private applyFactorySearchDisabledState(): void {
167	    if (this.loadingFactories || (this.isVendor && this.factories.length <= 1)) {
168	      this.factorySearchCtrl.disable({ emitEvent: false });
169	    } else {
170	      this.factorySearchCtrl.enable({ emitEvent: false });
171	    }
172	  }
173	
174	  private factorySearchQueryFromValue(value: string | FactoryListRow | null): string {
175	    if (value == null) {
176	      return '';
177	    }
178	    if (typeof value === 'string') {
179	      return value;
180	    }
181	    return this.factoryLabel(value);
182	  }
183	
184	  private filterFactoryList(query: string): FactoryListRow[] {
185	    const q = query.trim().toLowerCase();
186	    if (!q) {
187	      return [...this.factories];
188	    }
189	    return this.factories.filter((f) => {
190	      const label = this.factoryLabel(f).toLowerCase();
191	      const name = (f.factory_name || '').toLowerCase();
192	      const nick = (f.factory_nickname || '').toLowerCase();
193	      return (
194	        label.includes(q) ||
195	        name.includes(q) ||
196	        nick.includes(q) ||
197	        String(f.id).includes(q)
198	      );
199	    });
200	  }
201	
202	  private setFactorySelection(f: FactoryListRow | null): void {
203	    if (!f) {
204	      this.factoryForm.patchValue({ factoryId: null }, { emitEvent: false });
205	      this.factorySearchCtrl.setValue('', { emitEvent: false });
206	      return;
207	    }
208	    this.factoryForm.patchValue({ factoryId: f.id }, { emitEvent: false });
209	    this.factorySearchCtrl.setValue(f, { emitEvent: false });
210	  }
211	
212	  onFactoryOptionSelected(event: MatAutocompleteSelectedEvent): void {
213	    const f = event.option.value as FactoryListRow;
214	    if (f) {
215	      this.setFactorySelection(f);
216	      this.onFactoryChange();
217	    }
218	  }
219	
220	  onFactorySearchBlur(): void {
221	    const raw = this.factorySearchCtrl.value;
222	    const q = this.factorySearchQueryFromValue(raw).trim();
223	    const id = this.factoryForm.get('factoryId')?.value;
224	    const selected = id != null ? this.factories.find((x) => x.id === id) : null;
225	    if (selected && this.factoryLabel(selected) === q) {
226	      return;
227	    }
228	    const exact =
229	      q === ''
230	        ? null
231	        : this.factories.find((x) => this.factoryLabel(x) === q);
232	    if (exact) {
233	      this.setFactorySelection(exact);
234	      this.onFactoryChange();
235	    } else {
236	      this.setFactorySelection(null);
237	      this.loadOrders();
238	    }
239	  }
240	
241	  private readTokenContext(): void {
242	    try {
243	      const token = localStorage.getItem('token');
244	      if (!token) {
245	        return;
246	      }
247	      const p = decode(token) as { role?: string; factory_id?: number };
248	      this.isVendor = p.role === 'vendor';
249	      if (p.role === 'vendor' && p.factory_id != null && !Number.isNaN(Number(p.factory_id))) {
250	        this.vendorFactoryId = Number(p.factory_id);
251	      }
252	    } catch {
253	      /* ignore */
254	    }
255	  }
256	
257	  private applyVendorFactoryPreset(): void {
258	    if (this.isVendor && this.vendorFactoryId != null && this.factories.some((f) => f.id === this.vendorFactoryId)) {
259	      const f = this.factories.find((x) => x.id === this.vendorFactoryId)!;
260	      this.setFactorySelection(f);
261	    }
262	  }
263	
264	  loadOrders(): void {
265	    const fid = this.factoryForm.get('factoryId')?.value;
266	    if (fid === null || fid === undefined) {
267	      this.prodOrders = [];
268	      this.prodOrderTotalCount = 0;
269	      this.factoryForm.patchValue({
270	        prodOrderId: null,
271	        materialArrivalDate: null,
272	        massProdStartDate: null,
273	        assemblyStartDate: null,
274	        actualProdComplete: null,
275	        packingStartDate: null,
276	        qcInspectionDate: null,
277	        actualEtd: null
278	      });
279	      if (!this.factorySearchQueryFromValue(this.factorySearchCtrl.value).trim()) {
280	        this.factorySearchCtrl.setValue('', { emitEvent: false });
281	      }
282	      this.loadingList = false;
283	      return;
284	    }
285	
286	    this.loadingList = true;
287	    const factoryIdParam = Number(fid);
288	    const startRow = 0;
289	    const endRow = 10000;
290	
291	    this.tracking
292	      .getFactoryProdOrderList(factoryIdParam, {
293	        startRow,
294	        endRow,
295	        filterModel: {}
296	      })
297	      .subscribe({
298	      next: (res: { rows?: FactoryProdOrderRow[]; totalCount?: number }) => {
299	        this.prodOrders = res?.rows || [];
300	        this.prodOrderTotalCount = res?.totalCount ?? this.prodOrders.length;
301	        this.loadingList = false;
302	        this.factoryForm.patchValue({
303	          prodOrderId: null,
304	          materialArrivalDate: null,
305	          massProdStartDate: null,
306	          assemblyStartDate: null,
307	          actualProdComplete: null,
308	          packingStartDate: null,
309	          qcInspectionDate: null,
310	          actualEtd: null
311	        });
312	      },
313	      error: () => {
314	        this.loadingList = false;
315	        this.snackBar.open('Could not load production orders', 'Dismiss', { duration: 5000 });
316	      }
317	    });
318	  }
319	
320	  loadSampleOffers(): void {
321	    const fid = this.factoryForm.get('factoryId')?.value;
322	    if (fid === null || fid === undefined) {
323	      this.recentOffers = [];
324	      return;
325	    }
326	
327	    this.loadingOffers = true;
328	    this.tracking.getSamples({
329	      startRow: 0,
330	      endRow: 10,
331	      filterModel: {
332	        origin: { filterType: 'text', type: 'equals', filter: 'factory_offer' },
333	        factory_id_fk: { filterType: 'number', type: 'equals', filter: Number(fid) }
334	      }
335	    }).subscribe({
336	      next: (res: { rows?: FactorySampleOfferRow[] }) => {
337	        this.recentOffers = res?.rows || [];
338	        this.loadingOffers = false;
339	      },
340	      error: () => {
341	        this.recentOffers = [];
342	        this.loadingOffers = false;
343	      }
344	    });
345	  }
346	
347	  onFactoryChange(): void {
348	    this.factoryForm.patchValue({
349	      prodOrderId: null,
350	      materialArrivalDate: null,
351	      massProdStartDate: null,
352	      assemblyStartDate: null,
353	      actualProdComplete: null,
354	      packingStartDate: null,
355	      qcInspectionDate: null,
356	      actualEtd: null
357	    });
358	    this.loadOrders();
359	    this.loadSampleOffers();
360	  }
361	
362	  factoryLabel(f: FactoryListRow): string {
363	    return (f.factory_name || f.factory_nickname || `Factory #${f.id}`).trim();
364	  }
365	
366	  /** Dropdown label: prod reference (business key), same field prod tracking uses; fallback for legacy rows. */
367	  productionOrderLabel(o: FactoryProdOrderRow): string {
368	    const ref = (o.prodReferenceNo || '').trim();
369	    if (ref) {
370	      return ref;
371	    }
372	    const po = (o.prodOrderNo || '').trim();
373	    if (po) {
374	      return po;
375	    }
376	    return `Order #${o.id}`;
377	  }
378	
379	  onProductionOrderChange(): void {
380	    const id = this.factoryForm.get('prodOrderId')?.value;
381	    const row = this.prodOrders.find((o) => o.id === id);
382	    if (!row) {
383	      return;
384	    }
385	    this.factoryForm.patchValue({
386	      materialArrivalDate: this.parseYmd(row.material_arrival_date),
387	      massProdStartDate: this.parseYmd(row.mass_prod_start_date),
388	      assemblyStartDate: this.parseYmd(row.assembly_start_date),
389	      actualProdComplete: this.parseYmd(row.actual_prod_complete),
390	      packingStartDate: this.parseYmd(row.packing_start_date),
391	      qcInspectionDate: this.parseYmd(row.qc_inspection_date),
392	      actualEtd: this.parseYmd(row.actual_etd)
393	    });
394	  }
395	
396	  private parseYmd(value: string | null | undefined): Date | null {
397	    if (!value) {
398	      return null;
399	    }
400	    const m = String(value).match(/^(\d{4})-(\d{2})-(\d{2})/);
401	    if (!m) {
402	      return null;
403	    }
404	    const y = Number(m[1]);
405	    const mo = Number(m[2]) - 1;
406	    const d = Number(m[3]);
407	    return new Date(y, mo, d);
408	  }
409	
410	  private fmtYmd(d: Date | null | undefined): string | null {
411	    if (!d) {
