constructor(
  public dialogRef: MatDialogRef<CreateDialogComponent>,
  private coreApi: itemService,
  @Inject(MAT_DIALOG_DATA) public data: { customers?: CustomerOption[]; factories?: FactoryOption[] } | null
) {
  this.customers = (data && data.customers ? data.customers : [])
    .filter((c: any) => c && c.customers_id != null)
    .map((c: any) => ({ customers_id: Number(c.customers_id), customers_name: c.customers_name || `Customer #${c.customers_id}` }));
  this.filteredCustomers$ = this.customerControl.valueChanges.pipe(
    startWith(''),
    map(value => this.filterCustomers(value))
  );
  this.filteredFactories$ = this.factoryControl.valueChanges.pipe(
    startWith(''),
    map(value => this.filterFactories(value))
  );
  // Prefer factories passed in via dialog data; otherwise load them directly.
  if (data && data.factories && data.factories.length) {
    this.factories = this.normalizeFactories(data.factories);
  } else {
    this.loadFactories();
  }
}

private loadFactories(): void {
  this.coreApi.listFactories().subscribe({
    next: list => {
      this.factories = this.normalizeFactories(list || []);
      // Re-emit so the (already-subscribed) filtered list reflects the load.
      this.factoryControl.setValue(this.factoryControl.value, { emitEvent: true });
    },
    error: () => { this.factories = []; }
  });
}

private normalizeFactories(list: any[]): FactoryOption[] {
  return (list || [])
    .filter(f => f && f.id != null)
    .map(f => ({
      id: Number(f.id),
      factory_name: f.factory_name ?? null,
      factory_nickname: f.factory_nickname ?? null
    }));
}

factoryLabel(f: FactoryOption): string {
  return (f.factory_name || f.factory_nickname || `Factory #${f.id}`).trim();
}

displayFactory(value: FactoryOption | string | null): string {
  if (!value) return '';
  if (typeof value === 'string') return value;
  return this.factoryLabel(value);
}

onFactorySelected(factory: FactoryOption): void {
  this.model.factory_id_fk = factory ? factory.id : null;
}

private filterFactories(value: FactoryOption | string | null): FactoryOption[] {
  const query = this.displayFactory(value).trim().toLowerCase();
  if (!query) return this.factories.slice(0, 50);
  return this.factories
    .filter(f => {
      const name = (f.factory_name || '').toLowerCase();
      const nick = (f.factory_nickname || '').toLowerCase();
      return name.includes(query) || nick.includes(query) || String(f.id).includes(query);
    })
    .slice(0, 50);
}

// Block scientific-notation / sign characters that type=number otherwise
// accepts (e.g. "12e5" -> 1,200,000). Plain digits, a single decimal point and
// editing/navigation keys are allowed; everything else is suppressed.
blockNonNumericKey(event: KeyboardEvent): void {
  if (['e', 'E', '+', '-'].includes(event.key)) {
    event.preventDefault();
  }
}

